<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Maze Bots</title>
<style>
  * { margin: 0; padding: 0; box-sizing: border-box; }
  body {
    background: #0d1117;
    color: #c9d1d9;
    font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif;
    display: flex;
    flex-direction: column;
    align-items: center;
    min-height: 100vh;
    padding: 24px;
  }
  #hud {
    display: flex;
    gap: 20px;
    align-items: center;
    margin-bottom: 20px;
    font-size: 16px;
  }
  #hud span {
    background: #161b22;
    padding: 10px 18px;
    border-radius: 8px;
    border: 1px solid #30363d;
    font-variant-numeric: tabular-nums;
  }
  #reset {
    background: #238636;
    color: white;
    border: none;
    padding: 10px 24px;
    border-radius: 8px;
    font-size: 15px;
    cursor: pointer;
    font-weight: 600;
    transition: background 0.15s;
  }
  #reset:hover { background: #2ea043; }
  #maze {
    border: 2px solid #30363d;
    border-radius: 4px;
    background: #010409;
    display: block;
  }
</style>
</head>
<body>
<div id="hud">
  <span id="completed">Completed: 0</span>
  <span id="timer">Time: 0ms</span>
  <button id="reset">Reset</button>
</div>
<canvas id="maze"></canvas>

<script>
(function() {
  const MAZE_W = 21;
  const MAZE_H = 21;
  const CELL = 20;
  const NUM_BOTS = 24;
  const STEP_MS = 50;
  const SPAWN = { x: 0, y: 0 };
  const EXIT = { x: MAZE_W - 1, y: MAZE_H - 1 };

  const canvas = document.getElementById('maze');
  const ctx = canvas.getContext('2d');
  const completedEl = document.getElementById('completed');
  const timerEl = document.getElementById('timer');
  const resetBtn = document.getElementById('reset');

  canvas.width = MAZE_W * CELL;
  canvas.height = MAZE_H * CELL;

  let maze = [];
  let bots = [];
  let completedCount = 0;
  let steps = 0;
  let running = false;
  let animId = null;

  function generateMaze() {
    maze = [];
    for (let y = 0; y < MAZE_H; y++) {
      maze[y] = [];
      for (let x = 0; x < MAZE_W; x++) {
        maze[y][x] = { w: [true, true, true, true], vis: false };
      }
    }
    const stack = [{ x: 0, y: 0 }];
    maze[0][0].vis = true;
    const dirs = [[0,-1],[1,0],[0,1],[-1,0]];
    while (stack.length) {
      const cur = stack[stack.length-1];
      const nb = [];
      for (const [dx,dy] of dirs) {
        const nx = cur.x+dx, ny = cur.y+dy;
        if (nx>=0 && nx<MAZE_W && ny>=0 && ny<MAZE_H && !maze[ny][nx].vis) nb.push({x:nx,y:ny});
      }
      if (nb.length) {
        const next = nb[Math.floor(Math.random()*nb.length)];
        const dx = next.x-cur.x, dy = next.y-cur.y;
        if (dx===1){maze[cur.y][cur.x].w[1]=false;maze[next.y][next.x].w[3]=false;}
        if (dx===-1){maze[cur.y][cur.x].w[3]=false;maze[next.y][next.x].w[1]=false;}
        if (dy===1){maze[cur.y][cur.x].w[2]=false;maze[next.y][next.x].w[0]=false;}
        if (dy===-1){maze[cur.y][cur.x].w[0]=false;maze[next.y][next.x].w[2]=false;}
        maze[next.y][next.x].vis = true;
        stack.push(next);
      } else {
        stack.pop();
      }
    }
  }

  function bfs(sx, sy, ex, ey) {
    const vis = Array.from({length:MAZE_H},()=>Array(MAZE_W).fill(false));
    const q = [{x:sx,y:sy,p:[{x:sx,y:sy}]}];
    vis[sy][sx]=true;
    const dirs=[[0,-1],[1,0],[0,1],[-1,0]];
    while(q.length){
      const {x,y,p}=q.shift();
      if(x===ex&&y===ey)return p;
      const sd=[...dirs].sort(()=>Math.random()-0.5);
      for(const [dx,dy] of sd){
        const nx=x+dx,ny=y+dy;
        if(nx>=0&&nx<MAZE_W&&ny>=0&&ny<MAZE_H&&!vis[ny][nx]){
          const wi=dy===-1?0:dx===1?1:dy===1?2:3;
          if(!maze[y][x].w[wi]){
            vis[ny][nx]=true;
            q.push({x:nx,y:ny,p:[...p,{x:nx,y:ny}]});
          }
        }
      }
    }
    return null;
  }

  function initBots() {
    bots=[];
    for(let i=0;i<NUM_BOTS;i++){
      const path=bfs(SPAWN.x,SPAWN.y,EXIT.x,EXIT.y);
      bots.push({
        x:SPAWN.x, y:SPAWN.y,
        path:path||[], pathIdx:0,
        done:false,
        color:`hsl(${(i*15)%360},70%,58%)`,
        delay:Math.floor(Math.random()*12)
      });
    }
  }

  function render() {
    ctx.clearRect(0,0,canvas.width,canvas.height);
    for(let y=0;y<MAZE_H;y++){
      for(let x=0;x<MAZE_W;x++){
        const px=x*CELL, py=y*CELL;
        ctx.fillStyle='#0d1117';
        ctx.fillRect(px,py,CELL,CELL);
        const c=maze[y][x];
        ctx.strokeStyle='#4a90d9';
        ctx.lineWidth=2;
        if(c.w[0]){ctx.beginPath();ctx.moveTo(px,py);ctx.lineTo(px+CELL,py);ctx.stroke();}
        if(c.w[1]){ctx.beginPath();ctx.moveTo(px+CELL,py);ctx.lineTo(px+CELL,py+CELL);ctx.stroke();}
        if(c.w[2]){ctx.beginPath();ctx.moveTo(px,py+CELL);ctx.lineTo(px+CELL,py+CELL);ctx.stroke();}
        if(c.w[3]){ctx.beginPath();ctx.moveTo(px,py);ctx.lineTo(px,py+CELL);ctx.stroke();}
      }
    }
    ctx.fillStyle='#00ff88';
    ctx.fillRect(SPAWN.x*CELL+3,SPAWN.y*CELL+3,CELL-6,CELL-6);
    ctx.fillStyle='#ff4444';
    ctx.fillRect(EXIT.x*CELL+3,EXIT.y*CELL+3,CELL-6,CELL-6);
    for(const b of bots){
      if(b.done)continue;
      const cx=b.x*CELL+CELL/2, cy=b.y*CELL+CELL/2;
      const r=CELL*0.38;
      ctx.beginPath();
      ctx.arc(cx,cy,r,0,Math.PI*2);
      ctx.fillStyle=b.color;
      ctx.fill();
      ctx.strokeStyle='rgba(255,255,255,0.25)';
      ctx.lineWidth=1;
      ctx.stroke();
    }
  }

  function updateHUD(){
    completedEl.textContent=`Completed: ${completedCount}`;
    timerEl.textContent=`Time: ${steps*STEP_MS}ms`;
  }

  function tick(n){
    for(let i=0;i<n;i++){
      steps++;
      for(const b of bots){
        if(!b.done && b.delay<=steps){
          if(b.pathIdx<b.path.length-1){
            b.pathIdx++;
            b.x=b.path[b.pathIdx].x;
            b.y=b.path[b.pathIdx].y;
            if(b.x===EXIT.x&&b.y===EXIT.y){b.done=true;completedCount++;}
          }
        }
      }
    }
    updateHUD();
    render();
  }

  function animate(){
    if(!running)return;
    tick(1);
    animId=requestAnimationFrame(animate);
  }

  function reset(){
    if(animId)cancelAnimationFrame(animId);
    running=false;
    steps=0;completedCount=0;
    generateMaze();
    initBots();
    updateHUD();
    render();
  }

  function start(){
    running=true;
    animId=requestAnimationFrame(animate);
  }

  window.game={
    get bots(){return bots;},
    get completed(){return completedCount;},
    get elapsedMs(){return steps*STEP_MS;},
    tick:tick,
    reset:reset
  };

  generateMaze();
  initBots();
  updateHUD();
  render();
  start();
  resetBtn.addEventListener('click',reset);
})();
</script>
</body>
</html>
